<?php
declare(strict_types=1);namespace App\Controllers\Panel;use App\Controllers\BaseController;use App\Libraries\AuditLogger;use App\Models\CommissionPeriodModel;use App\Models\CommissionRuleModel;use App\Models\EmployeeModel;use App\Services\CommissionService;use CodeIgniter\Exceptions\PageNotFoundException;use CodeIgniter\HTTP\RedirectResponse;use RuntimeException;use Throwable;class Commissions extends BaseController
{
 public function index():string{$this->requireView();$db=db_connect();$entries=$db->table('commission_entries ce')->select('ce.*,cr.name AS rule_name,sd.document_number,sd.created_at AS document_date,e.full_name')->join('commission_rules cr','cr.id=ce.commission_rule_id')->join('sales_documents sd','sd.id=ce.sales_document_id')->join('employees e','e.id=ce.sales_employee_id');if(!$this->canManage())$entries->where('ce.sales_employee_id',$this->employeeId()??0);return view('panel/commissions/index',['title'=>'Primler | FORMMIX','pageTitle'=>'Primler','activeNav'=>'commissions','entries'=>$entries->orderBy('ce.created_at','DESC')->get()->getResultArray(),'rules'=>(new CommissionRuleModel())->orderBy('starts_on','DESC')->findAll(),'periods'=>(new CommissionPeriodModel())->orderBy('starts_on','DESC')->findAll(),'employees'=>(new EmployeeModel())->where('is_active',1)->orderBy('full_name')->findAll(),'categories'=>$db->table('product_categories')->where('is_active',1)->orderBy('name')->get()->getResultArray(),'canManage'=>$this->canManage()]);}
 public function storeRule():RedirectResponse{$this->requireManage();$rate=$this->decimal($this->request->getPost('rate_percent'));$type=(string)$this->request->getPost('base_type');if($rate<=0||$rate>100||!in_array($type,['sales','profit'],true))return redirect()->back()->withInput()->with('errors',['rule'=>'Geçerli bir matrah ve %0-100 arası oran girin.']);$model=new CommissionRuleModel();$data=['name'=>trim((string)$this->request->getPost('name')),'base_type'=>$type,'rate_percent'=>$rate,'employee_id'=>(int)$this->request->getPost('employee_id')?:null,'product_category_id'=>(int)$this->request->getPost('product_category_id')?:null,'starts_on'=>$this->date((string)$this->request->getPost('starts_on')),'ends_on'=>$this->date((string)$this->request->getPost('ends_on'),true),'is_active'=>1,'created_by_user_id'=>auth()->id()];if(!$data['name']||!$data['starts_on']||!$model->insert($data))return redirect()->back()->withInput()->with('errors',['rule'=>implode(' ',$model->errors())?:'Kural bilgileri eksik.']);$id=(int)$model->getInsertID();(new AuditLogger())->record('commission.rule_created','commission_rule',$id,null,$data);return redirect()->back()->with('message','Prim kuralı kaydedildi.');}
 public function calculate():RedirectResponse{$this->requireManage();try{$count=(new CommissionService())->calculate();return redirect()->back()->with('message',$count.' yeni prim kaydı hesaplandı; mevcut kayıtlar korunarak güncellendi.');}catch(Throwable $e){return redirect()->back()->with('errors',['calculate'=>$e->getMessage()]);}}
 public function storePeriod():RedirectResponse{$this->requireManage();$start=$this->date((string)$this->request->getPost('starts_on'));$end=$this->date((string)$this->request->getPost('ends_on'));if(!$start||!$end||$end<$start)return redirect()->back()->with('errors',['period'=>'Geçerli dönem tarihleri girin.']);$model=new CommissionPeriodModel();$code='PRM-'.str_replace('-','',$start).'-'.str_replace('-','',$end);if(!$model->insert(['period_code'=>$code,'starts_on'=>$start,'ends_on'=>$end,'status'=>'closed','closed_by_user_id'=>auth()->id(),'closed_at'=>date('Y-m-d H:i:s')]))return redirect()->back()->with('errors',['period'=>'Bu dönem daha önce kapatılmış olabilir.']);$id=(int)$model->getInsertID();db_connect()->query('UPDATE commission_entries SET commission_period_id = ? WHERE status = ? AND commission_period_id IS NULL AND sales_document_id IN (SELECT id FROM sales_documents WHERE created_at >= ? AND created_at <= ?)',[$id,'earned',$start.' 00:00:00',$end.' 23:59:59']);(new AuditLogger())->record('commission.period_closed','commission_period',$id,null,['starts_on'=>$start,'ends_on'=>$end]);return redirect()->back()->with('message','Prim dönemi kapatıldı.');}
 public function payPeriod(int $id):RedirectResponse{$this->requireManage();$model=new CommissionPeriodModel();$period=$model->find($id);if(!$period||$period['status']!=='closed')throw PageNotFoundException::forPageNotFound();$now=date('Y-m-d H:i:s');$model->update($id,['status'=>'paid','paid_at'=>$now]);db_connect()->table('commission_entries')->where('commission_period_id',$id)->where('status','earned')->update(['status'=>'paid','updated_at'=>$now]);(new AuditLogger())->record('commission.period_paid','commission_period',$id,['status'=>'closed'],['status'=>'paid']);return redirect()->back()->with('message','Dönem primleri ödendi olarak işaretlendi.');}
 private function canManage():bool{return auth()->user()?->can('commissions.manage')??false;}private function requireManage():void{if(!$this->canManage())throw PageNotFoundException::forPageNotFound();}private function requireView():void{if(!$this->canManage()&&!(auth()->user()?->can('commissions.view-all')??false)&&!(auth()->user()?->can('commissions.view-own')??false))throw PageNotFoundException::forPageNotFound();}private function employeeId():?int{$row=(new EmployeeModel())->where('user_id',auth()->id())->first();return$row?(int)$row['id']:null;}private function decimal(mixed $v):float{$v=str_replace(',','.',trim((string)$v));return is_numeric($v)?(float)$v:0;}private function date(string $v,bool $nullable=false):?string{return preg_match('/^\d{4}-\d{2}-\d{2}$/',$v)?$v:($nullable&&$v===''?null:null);}
}
